    if ($host = www.technodel.net) {
        return 301 https://technodel.net$request_uri;
    }

    root /var/www/technodel.net/public_html;
    index under-construction.html;

    location = /under-construction.html {
        try_files $uri =404;
    }

    # Allow WordPress static assets so product pages keep their styles/scripts
    location ^~ /wp-content/ {
        try_files $uri =404;
        expires 1h;
        add_header Cache-Control "public";
    }

    location ^~ /wp-includes/ {
        try_files $uri =404;
        expires 1h;
        add_header Cache-Control "public";
    }

    # Allow WooCommerce product pages through
    location ~ ^/product/ {
        try_files $uri $uri/ /index.php?$args;
    }

    # Allow WordPress REST API
    location ~ ^/wp-json/ {
        try_files $uri $uri/ /index.php?$args;
    }

    # PHP processing
    location ~ \.php$ {
        try_files $uri =404;
        fastcgi_split_path_info ^(.+\.php)(/.+)$;
        fastcgi_pass unix:/run/php/php8.3-fpm.sock;
        fastcgi_index index.php;
        include fastcgi_params;
        fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;
    }

    location / {
        try_files /under-construction.html =503;
    }
}
